CREATE TABLE users (id INT AUTO_INCREMENT PRIMARY KEY, username VARCHAR(50) NOT NULL UNIQUE, password VARCHAR(255) NOT NULL, name VARCHAR(120) NOT NULL, email VARCHAR(160) NULL, role ENUM('administrator','vendor','general_consultant') NOT NULL, is_active TINYINT(1) NOT NULL DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE categories (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120) NOT NULL, description TEXT NULL);
CREATE TABLE warehouses (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120) NOT NULL, location VARCHAR(255) NULL);
CREATE TABLE products (id INT AUTO_INCREMENT PRIMARY KEY, category_id INT NULL, sku VARCHAR(80) NOT NULL UNIQUE, name VARCHAR(150) NOT NULL, description TEXT NULL, stock DECIMAL(14,2) NOT NULL DEFAULT 0, stock_min DECIMAL(14,2) NOT NULL DEFAULT 0, cost DECIMAL(14,2) NOT NULL DEFAULT 0, price DECIMAL(14,2) NOT NULL DEFAULT 0, currency_code VARCHAR(10) NOT NULL DEFAULT 'USD', status VARCHAR(20) NOT NULL DEFAULT 'active', deleted_at DATETIME NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_products_category FOREIGN KEY (category_id) REFERENCES categories(id) ON DELETE SET NULL);
CREATE TABLE warehouse_stock (id INT AUTO_INCREMENT PRIMARY KEY, product_id INT NOT NULL, warehouse_id INT NOT NULL, stock DECIMAL(14,2) NOT NULL DEFAULT 0, UNIQUE KEY uk_product_warehouse(product_id, warehouse_id), CONSTRAINT fk_ws_product FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE, CONSTRAINT fk_ws_warehouse FOREIGN KEY (warehouse_id) REFERENCES warehouses(id) ON DELETE CASCADE);
CREATE TABLE inventory_movements (id INT AUTO_INCREMENT PRIMARY KEY, product_id INT NOT NULL, warehouse_id INT NOT NULL, movement_type VARCHAR(50) NOT NULL, quantity DECIMAL(14,2) NOT NULL, reference VARCHAR(100) NULL, notes TEXT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_im_product FOREIGN KEY (product_id) REFERENCES products(id), CONSTRAINT fk_im_warehouse FOREIGN KEY (warehouse_id) REFERENCES warehouses(id));
CREATE TABLE warehouse_transfers (id INT AUTO_INCREMENT PRIMARY KEY, product_id INT NOT NULL, from_warehouse_id INT NOT NULL, to_warehouse_id INT NOT NULL, quantity DECIMAL(14,2) NOT NULL, reference VARCHAR(80) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_wt_product FOREIGN KEY (product_id) REFERENCES products(id), CONSTRAINT fk_wt_from FOREIGN KEY (from_warehouse_id) REFERENCES warehouses(id), CONSTRAINT fk_wt_to FOREIGN KEY (to_warehouse_id) REFERENCES warehouses(id));
CREATE TABLE suppliers (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(150) NOT NULL, document VARCHAR(80) NULL, phone VARCHAR(80) NULL, email VARCHAR(150) NULL, address TEXT NULL, is_active TINYINT(1) NOT NULL DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE purchases (id INT AUTO_INCREMENT PRIMARY KEY, supplier_id INT NOT NULL, warehouse_id INT NULL, doc_number VARCHAR(80) NOT NULL, purchase_date DATE NOT NULL, due_date DATE NULL, currency_code VARCHAR(10) NOT NULL, exchange_rate DECIMAL(14,4) NOT NULL DEFAULT 1, subtotal_original DECIMAL(14,2) NOT NULL DEFAULT 0, total_original DECIMAL(14,2) NOT NULL DEFAULT 0, amount_paid_original DECIMAL(14,2) NOT NULL DEFAULT 0, balance_original DECIMAL(14,2) NOT NULL DEFAULT 0, subtotal_converted DECIMAL(14,2) NOT NULL DEFAULT 0, total_converted DECIMAL(14,2) NOT NULL DEFAULT 0, amount_paid_converted DECIMAL(14,2) NOT NULL DEFAULT 0, balance_converted DECIMAL(14,2) NOT NULL DEFAULT 0, notes TEXT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, status VARCHAR(20) NOT NULL DEFAULT 'active', payment_status VARCHAR(20) NOT NULL DEFAULT 'pending', cancelled_at DATETIME NULL, cancellation_reason TEXT NULL, CONSTRAINT fk_p_supplier FOREIGN KEY (supplier_id) REFERENCES suppliers(id), CONSTRAINT fk_p_warehouse FOREIGN KEY (warehouse_id) REFERENCES warehouses(id));
CREATE TABLE purchase_items (id INT AUTO_INCREMENT PRIMARY KEY, purchase_id INT NOT NULL, product_id INT NOT NULL, quantity DECIMAL(14,2) NOT NULL, cost_original DECIMAL(14,2) NOT NULL, cost_converted DECIMAL(14,2) NOT NULL, total_original DECIMAL(14,2) NOT NULL, total_converted DECIMAL(14,2) NOT NULL, CONSTRAINT fk_pi_purchase FOREIGN KEY (purchase_id) REFERENCES purchases(id) ON DELETE CASCADE, CONSTRAINT fk_pi_product FOREIGN KEY (product_id) REFERENCES products(id));
CREATE TABLE expense_categories (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120) NOT NULL);
CREATE TABLE expenses (id INT AUTO_INCREMENT PRIMARY KEY, category_id INT NOT NULL, expense_date DATE NOT NULL, reference VARCHAR(80) NOT NULL, description TEXT NULL, currency_code VARCHAR(10) NOT NULL, exchange_rate DECIMAL(14,4) NOT NULL DEFAULT 1, amount_original DECIMAL(14,2) NOT NULL, amount_converted DECIMAL(14,2) NOT NULL, payment_method VARCHAR(40) NOT NULL DEFAULT 'cash', treasury_account_id INT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_exp_category FOREIGN KEY (category_id) REFERENCES expense_categories(id));
CREATE TABLE cash_accounts (id INT AUTO_INCREMENT PRIMARY KEY, account_code VARCHAR(20) NOT NULL, account_name VARCHAR(120) NOT NULL, method_type VARCHAR(40) NOT NULL, currency_code VARCHAR(10) NOT NULL, opening_balance DECIMAL(14,2) NOT NULL DEFAULT 0, is_active TINYINT(1) NOT NULL DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY uniq_cash_account_method_currency(method_type, currency_code));
CREATE TABLE cash_movements (id INT AUTO_INCREMENT PRIMARY KEY, cash_account_id INT NOT NULL, movement_date DATE NOT NULL, direction VARCHAR(10) NOT NULL, currency_code VARCHAR(10) NOT NULL, exchange_rate DECIMAL(14,4) NOT NULL DEFAULT 1, amount_original DECIMAL(14,2) NOT NULL, amount_converted DECIMAL(14,2) NOT NULL, source_type VARCHAR(40) NULL, source_id INT NULL, reference VARCHAR(120) NOT NULL, notes TEXT NULL, is_reversed TINYINT(1) NOT NULL DEFAULT 0, reversed_at DATETIME NULL, reversal_reason TEXT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_cash_movements_account FOREIGN KEY (cash_account_id) REFERENCES cash_accounts(id));
CREATE TABLE clients (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(150) NOT NULL, document VARCHAR(80) NULL, phone VARCHAR(80) NULL, email VARCHAR(150) NULL, address TEXT NULL);
CREATE TABLE invoices (id INT AUTO_INCREMENT PRIMARY KEY, client_id INT NOT NULL, invoice_number VARCHAR(80) NOT NULL, invoice_date DATE NOT NULL, due_date DATE NULL, currency_code VARCHAR(10) NOT NULL, exchange_rate DECIMAL(14,4) NOT NULL DEFAULT 1, subtotal_original DECIMAL(14,2) NOT NULL DEFAULT 0, tax_original DECIMAL(14,2) NOT NULL DEFAULT 0, total_original DECIMAL(14,2) NOT NULL DEFAULT 0, amount_paid_original DECIMAL(14,2) NOT NULL DEFAULT 0, balance_original DECIMAL(14,2) NOT NULL DEFAULT 0, subtotal_converted DECIMAL(14,2) NOT NULL DEFAULT 0, tax_converted DECIMAL(14,2) NOT NULL DEFAULT 0, total_converted DECIMAL(14,2) NOT NULL DEFAULT 0, amount_paid_converted DECIMAL(14,2) NOT NULL DEFAULT 0, balance_converted DECIMAL(14,2) NOT NULL DEFAULT 0, notes TEXT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, status VARCHAR(20) NOT NULL DEFAULT 'active', payment_status VARCHAR(20) NOT NULL DEFAULT 'pending', cancelled_at DATETIME NULL, cancellation_reason TEXT NULL, CONSTRAINT fk_i_client FOREIGN KEY (client_id) REFERENCES clients(id));
CREATE TABLE invoice_items (id INT AUTO_INCREMENT PRIMARY KEY, invoice_id INT NOT NULL, product_id INT NOT NULL, warehouse_id INT NOT NULL, quantity DECIMAL(14,2) NOT NULL, price_original DECIMAL(14,2) NOT NULL, price_converted DECIMAL(14,2) NOT NULL, total_original DECIMAL(14,2) NOT NULL, total_converted DECIMAL(14,2) NOT NULL, CONSTRAINT fk_ii_invoice FOREIGN KEY (invoice_id) REFERENCES invoices(id) ON DELETE CASCADE, CONSTRAINT fk_ii_product FOREIGN KEY (product_id) REFERENCES products(id), CONSTRAINT fk_ii_warehouse FOREIGN KEY (warehouse_id) REFERENCES warehouses(id));
CREATE TABLE delivery_notes (id INT AUTO_INCREMENT PRIMARY KEY, client_id INT NOT NULL, note_number VARCHAR(80) NOT NULL, note_date DATE NOT NULL, due_date DATE NULL, currency_code VARCHAR(10) NOT NULL DEFAULT 'USD', exchange_rate DECIMAL(14,4) NOT NULL DEFAULT 1, subtotal_original DECIMAL(14,2) NOT NULL DEFAULT 0, total_original DECIMAL(14,2) NOT NULL DEFAULT 0, amount_paid_original DECIMAL(14,2) NOT NULL DEFAULT 0, balance_original DECIMAL(14,2) NOT NULL DEFAULT 0, subtotal_converted DECIMAL(14,2) NOT NULL DEFAULT 0, total_converted DECIMAL(14,2) NOT NULL DEFAULT 0, amount_paid_converted DECIMAL(14,2) NOT NULL DEFAULT 0, balance_converted DECIMAL(14,2) NOT NULL DEFAULT 0, notes TEXT NULL, status VARCHAR(20) NOT NULL DEFAULT 'active', payment_status VARCHAR(20) NOT NULL DEFAULT 'pending', cancelled_at DATETIME NULL, cancellation_reason TEXT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_dn_client FOREIGN KEY (client_id) REFERENCES clients(id));
CREATE TABLE delivery_note_items (id INT AUTO_INCREMENT PRIMARY KEY, delivery_note_id INT NOT NULL, product_id INT NOT NULL, warehouse_id INT NOT NULL, quantity DECIMAL(14,2) NOT NULL, price_original DECIMAL(14,2) NOT NULL DEFAULT 0, price_converted DECIMAL(14,2) NOT NULL DEFAULT 0, total_original DECIMAL(14,2) NOT NULL DEFAULT 0, total_converted DECIMAL(14,2) NOT NULL DEFAULT 0, CONSTRAINT fk_dni_note FOREIGN KEY (delivery_note_id) REFERENCES delivery_notes(id) ON DELETE CASCADE, CONSTRAINT fk_dni_product FOREIGN KEY (product_id) REFERENCES products(id), CONSTRAINT fk_dni_warehouse FOREIGN KEY (warehouse_id) REFERENCES warehouses(id));
CREATE TABLE invoice_payments (id INT AUTO_INCREMENT PRIMARY KEY, invoice_id INT NOT NULL, payment_date DATE NOT NULL, reference VARCHAR(120) NOT NULL, payment_method VARCHAR(40) NOT NULL DEFAULT 'cash', currency_code VARCHAR(10) NOT NULL, exchange_rate DECIMAL(14,4) NOT NULL DEFAULT 1, amount_original DECIMAL(14,2) NOT NULL, amount_converted DECIMAL(14,2) NOT NULL, applied_original DECIMAL(14,2) NOT NULL, applied_converted DECIMAL(14,2) NOT NULL, treasury_account_id INT NULL, notes TEXT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_invoice_payments_invoice FOREIGN KEY (invoice_id) REFERENCES invoices(id) ON DELETE CASCADE, CONSTRAINT fk_invoice_payments_account FOREIGN KEY (treasury_account_id) REFERENCES cash_accounts(id));
CREATE TABLE purchase_payments (id INT AUTO_INCREMENT PRIMARY KEY, purchase_id INT NOT NULL, payment_date DATE NOT NULL, reference VARCHAR(120) NOT NULL, payment_method VARCHAR(40) NOT NULL DEFAULT 'cash', currency_code VARCHAR(10) NOT NULL, exchange_rate DECIMAL(14,4) NOT NULL DEFAULT 1, amount_original DECIMAL(14,2) NOT NULL, amount_converted DECIMAL(14,2) NOT NULL, applied_original DECIMAL(14,2) NOT NULL, applied_converted DECIMAL(14,2) NOT NULL, treasury_account_id INT NULL, notes TEXT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_purchase_payments_purchase FOREIGN KEY (purchase_id) REFERENCES purchases(id) ON DELETE CASCADE, CONSTRAINT fk_purchase_payments_account FOREIGN KEY (treasury_account_id) REFERENCES cash_accounts(id));
CREATE TABLE delivery_note_payments (id INT AUTO_INCREMENT PRIMARY KEY, delivery_note_id INT NOT NULL, payment_date DATE NOT NULL, reference VARCHAR(120) NOT NULL, payment_method VARCHAR(40) NOT NULL DEFAULT 'cash', currency_code VARCHAR(10) NOT NULL, exchange_rate DECIMAL(14,4) NOT NULL DEFAULT 1, amount_original DECIMAL(14,2) NOT NULL, amount_converted DECIMAL(14,2) NOT NULL, applied_original DECIMAL(14,2) NOT NULL, applied_converted DECIMAL(14,2) NOT NULL, treasury_account_id INT NULL, notes TEXT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_delivery_note_payments_note FOREIGN KEY (delivery_note_id) REFERENCES delivery_notes(id) ON DELETE CASCADE, CONSTRAINT fk_delivery_note_payments_account FOREIGN KEY (treasury_account_id) REFERENCES cash_accounts(id));
CREATE TABLE exchange_rates (id INT AUTO_INCREMENT PRIMARY KEY, rate_date DATE NOT NULL, currency_from VARCHAR(10) NOT NULL, currency_to VARCHAR(10) NOT NULL, rate DECIMAL(14,4) NOT NULL);
CREATE TABLE settings (id INT AUTO_INCREMENT PRIMARY KEY, key_name VARCHAR(100) NOT NULL UNIQUE, value VARCHAR(255) NOT NULL);
